-- ============================================================
-- PACÍFICO REPUESTOS - Datos reales de producción
-- Migrados desde SQL Server local (pacifico_db) a PostgreSQL
-- Generado automáticamente a partir de la base de datos real
-- PostgreSQL
-- ============================================================
-- Este script inserta los datos REALES (188 productos, marcas,
-- modelos, generaciones, motores, categorias, inventario,
-- imagenes_producto y compatibilidades) preservando los IDs
-- originales de SQL Server para mantener la integridad de las
-- llaves foraneas. Reemplaza a 02_seed_data.sql para produccion.
--
-- Orden de ejecucion: despues de 01_ddl_create.sql
-- (respeta el orden de dependencias por llave foranea)
-- ============================================================

-- ===== MARCAS =====
-- ===== MODELOS =====
-- ===== GENERACIONES =====
-- ===== MOTORES =====
-- ===== CATEGORIAS =====
-- ===== PRODUCTOS =====
-- ===== INVENTARIO =====
-- ===== IMAGENES_PRODUCTO =====
-- ===== COMPATIBILIDADES =====

-- ============================================================
-- Reiniciar las secuencias de autoincremento para que los
-- proximos INSERT generados por la aplicacion continuen
-- despues del maximo id importado (evita choques de llave)
-- ============================================================
SELECT setval(pg_get_serial_sequence('marcas','id'), (SELECT COALESCE(MAX(id),1) FROM marcas));
SELECT setval(pg_get_serial_sequence('modelos','id'), (SELECT COALESCE(MAX(id),1) FROM modelos));
SELECT setval(pg_get_serial_sequence('generaciones','id'), (SELECT COALESCE(MAX(id),1) FROM generaciones));
SELECT setval(pg_get_serial_sequence('motores','id'), (SELECT COALESCE(MAX(id),1) FROM motores));
SELECT setval(pg_get_serial_sequence('categorias','id'), (SELECT COALESCE(MAX(id),1) FROM categorias));
SELECT setval(pg_get_serial_sequence('productos','id'), (SELECT COALESCE(MAX(id),1) FROM productos));
SELECT setval(pg_get_serial_sequence('inventario','id'), (SELECT COALESCE(MAX(id),1) FROM inventario));
SELECT setval(pg_get_serial_sequence('imagenes_producto','id'), (SELECT COALESCE(MAX(id),1) FROM imagenes_producto));
SELECT setval(pg_get_serial_sequence('compatibilidades','id'), (SELECT COALESCE(MAX(id),1) FROM compatibilidades));

SELECT 'Datos reales migrados correctamente.' AS resultado;
